22	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
23	const BLOCK_OF_THREE_PREMIUM = 60;
24	
25	const sumBasePremiums = (items: Item[]): number => {
26	  const counts = new Map<string, number>();
27	  let total = 0;
28	  for (const item of items) {
29	    if (COMPONENT_TYPES.has(item.type)) {
30	      counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
31	    } else {
32	      total += BASE_PREMIUM[item.type];
33	    }
34	  }
35	  for (const [type, count] of counts) {
36	    if (count === 3) {
37	      total += BLOCK_OF_THREE_PREMIUM;
38	    } else {
39	      total += count * BASE_PREMIUM[type];
40	    }
41	  }
42	  return total;
43	};
44	
45	const quotePremium = (items: Item[]): number => {
46	  const base = sumBasePremiums(items);
47	  const surcharge = base * INITIAL_ASSESSMENT_SURCHARGE_RATE;
48	  return Math.ceil(base + surcharge) + PROCESSING_FEE;
49	};
50	
51	export const runScenario = (input: Scenario): ScenarioResult => {
52	  const results = input.steps.map((step) => ({ premium: quotePremium(step.items) }));
53	  return { results };
54	};
