const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
const BLOCK_OF_THREE_PREMIUM = 60;

const priceComponentGroup = (type: string, count: number): number =>
  count === 3 ? BLOCK_OF_THREE_PREMIUM : count * BASE_PREMIUM[type];

const sumBasePremiums = (items: Item[]): number => {
  const componentCounts = new Map<string, number>();
  let total = 0;
  for (const item of items) {
    if (COMPONENT_TYPES.has(item.type)) {
      componentCounts.set(item.type, (componentCounts.get(item.type) ?? 0) + 1);
    } else {
      total += BASE_PREMIUM[item.type];
    }
  }
  for (const [type, count] of componentCounts) {
    total += priceComponentGroup(type, count);
  }
  return total;
};
